using UnityEngine;
using UnityEngine.UI;   // Para UI Text
using UnityEngine.Events;

public class PremiumPurchaseHandler : MonoBehaviour
{
    [Header("UI Elements")]
    public GameObject cryingCharacter;   // El prefab o objeto que representa al personaje llorando
    public Text messageText;             // Texto que mostrará el mensaje

    [Header("Purchase Settings")]
    public string premiumItemId = "premium_item_001";
    public bool hasPurchased = false;    // Se actualizará según tu sistema de pagos

