        if (!hasPurchased)
        {
            ShowSadCharacter();
        }
    }

    // Llamada cuando el niño intenta usar el ítem premium
    public void OnAttemptUsePremium()
    {
        if (!hasPurchased)
        {
            ShowSadCharacter();
        }
        else
        {
