## 2. Código de ejemplo (Unity C#)

```csharp
using UnityEngine;
using UnityEngine.UI;

public class PremiumItemHandler : MonoBehaviour
{
    [Header("UI Elements")]
    public GameObject cryingAnimation;   // Prefab o objeto con la animación de llanto
    public Text messageText;             // Texto que mostrará el mensaje
    public GameObject messagePanel;      // Panel que contiene el texto

    // Llamada cuando el jugador intenta usar el ítem premium
    public void TryUsePremiumItem()
    {
        if (!HasPurchasedPremium())
        {
            ShowCryingFeedback();
        }
        else
        {
            // Código para usar el ítem premium
        }
    }

    // Simulación de verificación de compra
    private bool HasPurchasedPremium()
    {
        // Aquí deberías integrar tu sistema de pagos real
        return false; // Para este ejemplo siempre falla
    }

    private void ShowCryingFeedback()
    {
        // 1. Activar animación de llanto
        if (cryingAnimation != null)
            cryingAnimation.SetActive(true);

        // 2. Mostrar mensaje
        if (messagePanel != null && messageText != null)
        {
            messageText.text = "Bobby está triste porque no lo ayudaste";
            messagePanel.SetActive(true);
        }

        // 3. Opcional: desactivar la animación después de unos segundos
        Invoke(nameof(HideCryingFeedback), 3f);
    }

    private void HideCryingFeedback()
    {
        if (cryingAnimation != null)
            cryingAnimation.SetActive(false);

        if (messagePanel != null)
            messagePanel.SetActive(false);
    }
}
```

